import json, os, subprocess, sys
queue='/root/.openclaw/workspace/webhook/queue/pending.json'
alerts=[]
if os.path.exists(queue):
    try:
        with open(queue,'r',encoding='utf-8') as f:
            data=json.load(f)
        if isinstance(data, dict):
            items=data.get('notifications') or data.get('pending') or data.get('items') or []
            if not isinstance(items,list):
                items=[]
        elif isinstance(data,list):
            items=data
        else:
            items=[]
        for i,it in enumerate(items,1):
            if not isinstance(it,dict):
                continue
            author=it.get('author') or it.get('user') or it.get('username') or 'unknown'
            text=it.get('text') or it.get('content') or it.get('body') or ''
            url=it.get('url') or it.get('link') or ''
            tid=it.get('tweet_id') or it.get('id') or ''
            alerts.append({'author':author,'text':text,'url':url,'tweet_id':tid})
        if alerts:
            with open(queue,'w',encoding='utf-8') as f:
                json.dump([],f)
            print('WEBHOOK_ALERTS_BEGIN')
            print(json.dumps(alerts,ensure_ascii=False))
            print('WEBHOOK_ALERTS_END')
        else:
            print('WEBHOOK_NONE')
    except Exception as e:
        print(f'WEBHOOK_PARSE_ERROR: {e}')
else:
    print('WEBHOOK_FILE_MISSING')

print('MISSED_MENTIONS_BEGIN')
res=subprocess.run(['/root/.openclaw/workspace/scripts/check_missed_mentions.py'],capture_output=True,text=True)
print('EXIT',res.returncode)
if res.stdout:
    print(res.stdout.strip())
if res.stderr:
    print('STDERR:')
    print(res.stderr.strip())
print('MISSED_MENTIONS_END')
